import{_ as t,c as a,o as d,a2 as e}from"./chunks/framework.fUIGTZnq.js";const u=JSON.parse('{"title":"产前测试（九联自研）流程完整描述","description":"","frontmatter":{"outline":[2,3]},"headers":[],"relativePath":"tools/um/pre-production-testing.md","filePath":"tools/um/pre-production-testing.md","lastUpdated":null}'),l={name:"tools/um/pre-production-testing.md"},r=e('<h1 id="产前测试-九联自研-流程完整描述" tabindex="-1">产前测试（九联自研）流程完整描述 <a class="header-anchor" href="#产前测试-九联自研-流程完整描述" aria-label="Permalink to &quot;产前测试（九联自研）流程完整描述&quot;">​</a></h1><p>更新时间：2024年1月3日</p><p>为了更快效率更高地完成产前测试任务，务必按照此流程来进行产前测试。</p><h2 id="一、任务承接" tabindex="-1">一、任务承接 <a class="header-anchor" href="#一、任务承接" aria-label="Permalink to &quot;一、任务承接&quot;">​</a></h2><p><a href="https://www.kdocs.cn/l/ck5TtPxlSXfy" target="_blank" rel="noreferrer">2023年的任务列表</a></p><p><a href="https://www.kdocs.cn/l/cbamnxd5MuQI" target="_blank" rel="noreferrer">2024年的任务列表</a></p><h2 id="二、资料准备" tabindex="-1">二、资料准备 <a class="header-anchor" href="#二、资料准备" aria-label="Permalink to &quot;二、资料准备&quot;">​</a></h2><h3 id="_1、软件版本及烧写包、镜像" tabindex="-1">1、软件版本及烧写包、镜像 <a class="header-anchor" href="#_1、软件版本及烧写包、镜像" aria-label="Permalink to &quot;1、软件版本及烧写包、镜像&quot;">​</a></h3><p>获取途径</p><ol><li>通过邮件搜索版本号获取SVN路径。</li><li>通过<a href="http://oldws.unionman.net/ws" target="_blank" rel="noreferrer">九联办公</a>-项目管理-软件项目清单 中查询项目信息， 获取SVN路径。</li><li>上述方式都无法找到资料，需要询问项目经理</li></ol><h4 id="移芯方案的烧写包需要重新打包" tabindex="-1">移芯方案的烧写包需要重新打包 <a class="header-anchor" href="#移芯方案的烧写包需要重新打包" aria-label="Permalink to &quot;移芯方案的烧写包需要重新打包&quot;">​</a></h4><p>重新打包的方法在获取校准综测和RFBin中说明。</p><h3 id="_2、获取校准综测脚本及rfbin信息" tabindex="-1">2、获取校准综测脚本及RFBin信息 <a class="header-anchor" href="#_2、获取校准综测脚本及rfbin信息" aria-label="Permalink to &quot;2、获取校准综测脚本及RFBin信息&quot;">​</a></h3><p>主要获取途径：<a href="./.html">\\\\192.168.136.3\\物联网事业部\\研发部\\02硬件开发\\5-RF版本管理</a></p><p>确认及获取校准综测脚本方式与芯片方案有很大关系，自研目前存在以下几种芯片方案。</p><h4 id="_1-asr芯片方案" tabindex="-1">1)ASR芯片方案 <a class="header-anchor" href="#_1-asr芯片方案" aria-label="Permalink to &quot;1)ASR芯片方案&quot;">​</a></h4><p>方案特点:</p><ul><li>使用客供工具+产测工具，脚本通过客供工具配置。此处不赘述。</li><li>RFBin集成在烧写包内。</li></ul><p>ASR机型较多，每个新机型或者新接手的机型必须要通过邮件以及向项目经理确认校准综测的脚本。</p><ol><li>有同机型时，沿用上一最近完成的产前测试任务的校准综测。</li><li>随时关注脚本更新情况，但基本上脚本稳定之后后续不会出现变动。</li></ol><h4 id="_2-移芯芯片方案" tabindex="-1">2)移芯芯片方案 <a class="header-anchor" href="#_2-移芯芯片方案" aria-label="Permalink to &quot;2)移芯芯片方案&quot;">​</a></h4><p>方案特点:</p><ul><li>使用集成客供二次开发包的产测工具，产测工具及客供配置都需要单独配置。</li><li>RFBin分离</li></ul><p>目前自研移芯有以下芯片型号</p><ul><li>EC616</li><li>EC616L(使用EC616S的配置)</li><li>EC618</li></ul><p>下表为最新的RFBin表</p><table><thead><tr><th>芯片型号</th><th>RFBin文件名</th><th>修改时间</th><th>MD5</th><th>备注</th></tr></thead><tbody><tr><td>EC616</td><td>MergeRfTable.bin</td><td>2020-07-24 11:07:00</td><td>EEAA68BF19EFC6F5EAD81C5A90F66FA6</td><td></td></tr><tr><td>EC616L</td><td>MergeRfTable_EC616s_1.bin</td><td>2022-11-22 11:24:50</td><td>E664F92450853FA25B03992D997DC775</td><td>038P03包里的Bin</td></tr><tr><td>EC616L</td><td>MergeRfTable_EC616s.bin</td><td>2021-12-06 15:55:20</td><td>19E5246C8EB3A2CFE94A71DA880C6DB1</td><td>旧烧写包发现此bin不做处理</td></tr><tr><td>EC618</td><td>Ec618RfOfflineTable_v6.0_NV7644_M1A1_20230327_UMA603_2b0.bin</td><td>2023-04-11 17:28:14</td><td>9B37412D686ADAA4B9607884BA97636D</td><td>UMA603 TNOLM</td></tr><tr><td>EC618</td><td>Ec618RfOfflineTable_v3.1_NV7644_M1A1_20230224_UMA603_EC618.bin</td><td>2023-02-24 09:34:18</td><td>05FBF98E25E12AA74B3D5F4DB597D842</td><td>UMA603_TNOLN</td></tr><tr><td>EC618</td><td>Ec618RfOfflineTable_v3.1_NV7644_M1A1_20221110_UMA603.bin</td><td>2022-12-23 09:58:00</td><td>BA83F56579B4E1D4A92C6F743E476304</td><td>UMA603-Q1_TNOLN</td></tr></tbody></table><p>下表为最新的校准综测脚本表（移芯校准综测工具已更新为7.4），后续产前测试都需要使用下表信息。</p><table><thead><tr><th>芯片型号</th><th>校准综测文件名</th><th>修改时间</th><th>MD5</th><th>备注</th></tr></thead><tbody><tr><td>EC616</td><td>EC616_#Cal&amp;Nst_RFTest.xml</td><td>2023-07-20 16:07:00</td><td>A2CF82CDAA980FCBFF07238F5672E06B</td><td></td></tr><tr><td>EC616S</td><td>EC616S_#Cal&amp;Nst_RFTest.xml</td><td>2023-07-20 16:07:00</td><td>7A39AF2C546079E7DBBC1B3E26418B9A</td><td>时间发生变化,内容不变</td></tr><tr><td>EC618</td><td>EC618_#Cal&amp;Nst_RFTest.xml</td><td>2023-09-25 08:47:11</td><td>F08B4B9A83DF87A9CBA4697517FB1355</td><td>UMA603_TNOLN<br> UMA603-Q1</td></tr><tr><td>EC618</td><td>EC618_#Cal&amp;Nst_RFTest.xml</td><td>2023-09-25 08:47:11</td><td>F08B4B9A83DF87A9CBA4697517FB1355</td><td>UMA603_TNOLM <br>与单卡内容一致但与硬件提供的存放路径不同，故单独列出</td></tr></tbody></table><h4 id="_3-海思芯片方案" tabindex="-1">3)海思芯片方案 <a class="header-anchor" href="#_3-海思芯片方案" aria-label="Permalink to &quot;3)海思芯片方案&quot;">​</a></h4><p>方案特点:</p><ul><li>使用集成Python环境产测工具，仪器配置在产测工具里配置，脚本需要根据<strong>机器型号</strong>参数来决定放置的目录。</li><li>RFBin集成在烧写包中</li></ul><p>获取途径</p><ul><li>沿用上一产前测试任务打包的产测工具中的脚本</li></ul><p>需要确认的信息</p><ul><li>calibration_tools\\CalConfig_V20.py中 80行左右的<code>BLE_CALIBRATION_BAND_SELECT</code>，如果是带蓝牙版本则<code>BLE_CALIBRATION_BAND_SELECT=[&#39;PATH_BLE&#39;]</code></li></ul><h3 id="_3、全功能单片机程序" tabindex="-1">3、全功能单片机程序 <a class="header-anchor" href="#_3、全功能单片机程序" aria-label="Permalink to &quot;3、全功能单片机程序&quot;">​</a></h3><p>获取途径</p><ol><li>邮件获取</li><li>沿用上一产前测试任务的单片机程序</li></ol><h3 id="_4、工具获取" tabindex="-1">4、工具获取 <a class="header-anchor" href="#_4、工具获取" aria-label="Permalink to &quot;4、工具获取&quot;">​</a></h3><h3 id="_5、订单配置" tabindex="-1">5、订单配置 <a class="header-anchor" href="#_5、订单配置" aria-label="Permalink to &quot;5、订单配置&quot;">​</a></h3><p>九联或为知</p><h3 id="_6、产测夹具兼容性确认" tabindex="-1">6、产测夹具兼容性确认 <a class="header-anchor" href="#_6、产测夹具兼容性确认" aria-label="Permalink to &quot;6、产测夹具兼容性确认&quot;">​</a></h3><h3 id="_7、" tabindex="-1">7、 <a class="header-anchor" href="#_7、" aria-label="Permalink to &quot;7、&quot;">​</a></h3>',44),i=[r];function o(h,n,_,s,c,p){return d(),a("div",null,i)}const A=t(l,[["render",o]]);export{u as __pageData,A as default};
